import { Request, Response } from "express";
import {
  selectItems,
  insertItem,
  updateItem,
  searchItems,
  ItemMasterRecord,
  selectItemByID,
} from "../../../models/IICSMA/itemMaster";
import { asyncHandler } from "../../../utils/asyncHandler";

// Get all items
export const getAllItems = asyncHandler(async (req: Request, res: Response) => {
  const selectAll = req.query.selectAll === "true";
  const currentPage = Number(req.query.currentPage) || 1;
  const itemsPerPage = Number(req.query.itemsPerPage) || 10;
  const nameCode = req.query.nameCode === "true";
  const name = req.query.name as string | undefined; // Optional name parameter for filtering

  try {
    const { items, totalItems } = await selectItems(
      selectAll,
      currentPage,
      itemsPerPage,
      nameCode,
      name // Pass the name parameter here
    );

    res.status(200).json({
      items,
      totalItems,
      currentPage,
      itemsPerPage,
    });
  } catch (error: any) {
    console.error("Error getting all items:", error);
    res.status(500).json({ message: "Internal Server Error" });
  }
});

// Get an item by its code
export const getItemByCode = asyncHandler(
  async (req: Request, res: Response) => {
    const { code } = req.params;
    try {
      const result = await selectItemByID(code);

      res.status(200).json(result);
    } catch (error: any) {
      console.error("Error getting item by code:", error);
      throw error;
    }
  }
);

// Search items by specific criteria
export const searchItemsByCriteria = asyncHandler(
  async (req: Request, res: Response) => {
    const searchData = req.query;

    try {
      const result = await searchItems(searchData);
      res.status(200).json(result);
    } catch (error: any) {
      console.error("Error searching items:", error);
      throw error;
    }
  }
);

// Create a new item
export const createItem = asyncHandler(async (req: Request, res: Response) => {
  const data: ItemMasterRecord = req.body;

  const mandatoryFields = [
    // { field: "itemCode", message: "Item Code" },
    { field: "itemName", message: "Item Name" },
    { field: "uomCode", message: "Unit of Measurement Code" },
    { field: "majorCategoryCode", message: "Major Category Code" },
    { field: "subCategoryCode", message: "Sub Category Code" },
    { field: "specCode", message: "Specification Code" },
    { field: "brandCode", message: "Brand Code" },
    { field: "catalogCode", message: "Catalog Code" },
    { field: "accGroupCode", message: "Account Group Code" },
    { field: "status", message: "Status" },
    { field: "waRate", message: "Weighted Average Rate" },
    { field: "avgCons", message: "Average Consumption" },
    { field: "leedTime", message: "Lead Time" },
    // { field: "closureDate", message: "Closure Date" },
  ];

  // Check for missing mandatory fields
  const missingFields = mandatoryFields
    .filter(({ field }) => !data[field as keyof ItemMasterRecord])
    .map(({ message }) => message);

  // If missing fields, throw an error
  if (missingFields.length > 0) {
    throw {
      status: 400,
      title: "BAD_REQUEST",
      message: `Missing mandatory fields: ${missingFields.join(", ")}`,
    };
  }

  try {
    const data: ItemMasterRecord = {
      ...req.body,
      ENTRY_DATE: "", // This will be handled by the database (SYSDATE)
    };

    const result = await insertItem(data);
    res.status(201).json(result);
  } catch (error: any) {
    console.error("Error creating item:", error);

    if (error.message.includes("Missing mandatory field")) {
      throw { status: 400, message: error.message };
    }

    throw error;
  }
});

// Update an existing item by its code
export const updateItemByCode = asyncHandler(
  async (req: Request, res: Response) => {
    const { code } = req.params;

    // Extract and validate the updated details
    const updatedDetails: Partial<ItemMasterRecord> = {
      ...req.body,
      MODIFY_DATE: new Date(), // This will be handled by the database (SYSDATE)
    };

    // Check for required fields and set defaults if necessary
    if (!updatedDetails.itemName) {
      throw { status: 400, message: "Item Name is required." };
    }

    const updatedItem: ItemMasterRecord = {
      itemCode: code,
      itemName: updatedDetails.itemName, // Required field
      uomCode: updatedDetails.uomCode || "", // Default to empty string if undefined
      majorCategoryCode: updatedDetails.majorCategoryCode || "", // Default to empty string if undefined
      subCategoryCode: updatedDetails.subCategoryCode || 0, // Default to 0 if undefined
      specCode: updatedDetails.specCode || "", // Default to empty string if undefined
      brandCode: updatedDetails.brandCode || "", // Default to empty string if undefined
      catalogCode: updatedDetails.catalogCode || "", // Default to empty string if undefined
      accGroupCode: updatedDetails.accGroupCode || "", // Default to empty string if undefined
      status: updatedDetails.status || "", // Default to empty string if undefined
      waRate: updatedDetails.waRate || 0, // Default to 0 if undefined
      avgCons: updatedDetails.avgCons || 0, // Default to 0 if undefined
      leedTime: updatedDetails.leedTime || 0, // Default to 0 if undefined
      closureDate: updatedDetails.closureDate || new Date(), // Default to current date if undefined
      entryUser: updatedDetails.entryUser || "", // Default to empty string if undefined
      modifyUser: updatedDetails.modifyUser || "", // Default to empty string if undefined
      entryDate: updatedDetails.entryDate || new Date(), // Default to current date if undefined
      modifyDate: updatedDetails.modifyDate || new Date(), // Default to current date if undefined
      hostName: updatedDetails.hostName || "", // Default to empty string if undefined
      ipAddress: updatedDetails.ipAddress || "", // Default to empty string if undefined
    };

    try {
      const result = await updateItem(updatedItem);
      res.status(200).json(result);
    } catch (error: any) {
      console.error("Error updating item:", error);
      throw error;
    }
  }
);

